import{_ as e}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as t,o,c as i,a2 as n}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Automatyczne tagowanie","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Other/auto-tagging.md","filePath":"pl-PL/Other/auto-tagging.md","lastUpdated":1781962217000}'),c={name:"pl-PL/Other/auto-tagging.md"};function p(r,a,d,s,l,g){return o(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="automatyczne-tagowanie" tabindex="-1">Automatyczne tagowanie <a class="header-anchor" href="#automatyczne-tagowanie" aria-label="Permalink to &quot;Automatyczne tagowanie&quot;">​</a></h1><p>Automatyczne tagowanie konfiguruje się w:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>Funkcja automatycznie generuje tagi obrazów. Są przydatne w wyszukiwaniu, filtrowaniu Random Image API, filtrowaniu publicznej galerii i kontroli dostępu według klasyfikacji wiekowej.</p><h2 id="co-potrafi-automatyczne-tagowanie" tabindex="-1">Co potrafi automatyczne tagowanie <a class="header-anchor" href="#co-potrafi-automatyczne-tagowanie" aria-label="Permalink to &quot;Co potrafi automatyczne tagowanie&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funkcja</th><th>Opis</th></tr></thead><tbody><tr><td>Generowanie tagów treści</td><td>Dodaje tagi dla osób, scen, obiektów, stylu artystycznego i podobnej zawartości wizualnej.</td></tr><tr><td>Generowanie tagów postaci</td><td>Przydatne dla obrazów anime i ilustracji.</td></tr><tr><td>Dodawanie tagów orientacji</td><td>Dodaje <code>landscape</code>, <code>portrait</code> albo <code>square</code>.</td></tr><tr><td>Dodawanie ratingu obrazu</td><td>Zapisuje wyniki <code>G/S/Q/E</code> dla treści ogólnej, wrażliwej, wątpliwej lub jednoznacznej.</td></tr><tr><td>Automatyczne tagowanie przy uploadzie</td><td>Nowo przesłane obrazy automatycznie trafiają do procesu tagowania.</td></tr><tr><td>Tagowanie zbiorcze</td><td>Dodaje tagi do starych obrazów we wszystkich katalogach lub wybranych katalogach.</td></tr></tbody></table><h2 id="co-przygotowac-przed-rozpoczeciem" tabindex="-1">Co przygotować przed rozpoczęciem <a class="header-anchor" href="#co-przygotowac-przed-rozpoczeciem" aria-label="Permalink to &quot;Co przygotować przed rozpoczęciem&quot;">​</a></h2><p>Przygotuj co najmniej jeden dostępny URL Hugging Face Space.</p><p>Zalecane podejście to zduplikowanie Space <code>wd-tagger</code> od SmilingWolf na własne konto Hugging Face:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Możesz tymczasowo użyć publicznego Space, ale publiczne Spaces są współdzielone przez wielu użytkowników i mogą mieć kolejki, spowolnienia albo przerwy. Zduplikowany Space na własnym koncie jest stabilniejszy do długotrwałego tagowania.</p><h2 id="duplikowanie-space-smilingwolf" tabindex="-1">Duplikowanie Space SmilingWolf <a class="header-anchor" href="#duplikowanie-space-smilingwolf" aria-label="Permalink to &quot;Duplikowanie Space SmilingWolf&quot;">​</a></h2><ol><li>Zaloguj się do Hugging Face.</li><li>Otwórz <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+e+`" alt="Publiczny Space SmilingWolf" loading="lazy"></p><ol start="3"><li>Kliknij menu z trzema kropkami w prawym górnym rogu.</li><li>Wybierz <code>Duplicate this Space</code>.</li><li>Zostaw domyślną nazwę Space albo wybierz własną, np. <code>wd-tagger</code>.</li><li>Ustaw widoczność na <code>Public</code>. Publiczne Spaces są łatwiejsze do wywołania przez ImgBed.</li><li>Na początku zostaw domyślny darmowy sprzęt. Zmień go później tylko wtedy, gdy kolejki będą wyraźnym problemem.</li><li>Utwórz Space i poczekaj na zakończenie builda.</li></ol><p>Po zakończeniu builda otwórz stronę swojego Space. URL zwykle wygląda tak:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Skopiuj adres z przeglądarki i wklej go do <code>Space URLs</code> w ImgBed.</p><h2 id="wpisywanie-wielu-space-url" tabindex="-1">Wpisywanie wielu Space URL <a class="header-anchor" href="#wpisywanie-wielu-space-url" aria-label="Permalink to &quot;Wpisywanie wielu Space URL&quot;">​</a></h2><p>Wpisuj jeden Space URL w każdym wierszu.</p><p>Przykłady:</p><table tabindex="0"><thead><tr><th>Wartość</th><th>Opis</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>Publiczny Space SmilingWolf. Dobry do tymczasowych testów.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>URL strony skopiowanego Space.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Twój zduplikowany Space.</td></tr></tbody></table><p>Możesz wpisać wiele URL-i. ImgBed używa wielu Spaces razem, co może poprawić szybkość.</p><p>Jeśli jeden Space jest tymczasowo niedostępny, pozostałe mogą nadal przetwarzać obrazy.</p><h2 id="ustawienia" tabindex="-1">Ustawienia <a class="header-anchor" href="#ustawienia" aria-label="Permalink to &quot;Ustawienia&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opcja</th><th>Rekomendacja</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Wpisz przygotowane URL-e Space. Użyj co najmniej jednego.</td></tr><tr><td>Katalog docelowy</td><td>Zostaw puste dla wszystkich katalogów. Wybierz katalog tylko wtedy, gdy chcesz przetworzyć konkretną ścieżkę.</td></tr><tr><td>Model rozpoznawania</td><td>Domyślnie zostaw <code>wd-swinv2-tagger-v3</code>.</td></tr><tr><td>Próg tagów ogólnych</td><td>Domyślna wartość działa dla większości obrazów. Niższa daje więcej tagów, wyższa mniej.</td></tr><tr><td>Próg tagów postaci</td><td>Domyślnie konserwatywny, pomaga unikać błędnych tagów postaci.</td></tr><tr><td>Automatyczny próg <code>MCut</code></td><td>Na początku zostaw wyłączony. Włącz, jeśli model ma sam zdecydować o liczbie tagów.</td></tr><tr><td>Automatyczne tagowanie przy uploadzie</td><td>Włącz, jeśli nowe obrazy mają automatycznie dostawać tagi.</td></tr><tr><td>Rozpocznij tagowanie</td><td>Ręczne tagowanie zbiorcze starych obrazów.</td></tr></tbody></table><h2 id="zalecane-wartosci-poczatkowe" tabindex="-1">Zalecane wartości początkowe <a class="header-anchor" href="#zalecane-wartosci-poczatkowe" aria-label="Permalink to &quot;Zalecane wartości początkowe&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opcja</th><th>Zalecana wartość</th></tr></thead><tbody><tr><td>Model rozpoznawania</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>Próg tagów ogólnych</td><td><code>0.35</code></td></tr><tr><td>Próg tagów postaci</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>Na początku wyłączony</td></tr><tr><td>Automatyczne tagowanie przy uploadzie</td><td>Włącz w razie potrzeby</td></tr></tbody></table><p>Jeśli tagów jest za dużo, lekko zwiększ próg ogólny.</p><p>Jeśli tagów jest za mało, lekko zmniejsz próg ogólny.</p><h2 id="tagowanie-zbiorcze" tabindex="-1">Tagowanie zbiorcze <a class="header-anchor" href="#tagowanie-zbiorcze" aria-label="Permalink to &quot;Tagowanie zbiorcze&quot;">​</a></h2><ol><li>Wypełnij <code>Space URLs</code>.</li><li>Wybierz katalog docelowy.</li><li>Kliknij rozpoczęcie tagowania.</li><li>Poczekaj na zakończenie postępu.</li></ol><p>Jeśli katalog docelowy jest pusty, ImgBed przetwarza wszystkie katalogi.</p><p>Tagowanie zbiorcze jest najlepsze dla starych obrazów. Dla nowych obrazów włącz automatyczne tagowanie przy uploadzie, aby nie uruchamiać go ręcznie za każdym razem.</p><h2 id="automatyczne-tagowanie-przy-uploadzie" tabindex="-1">Automatyczne tagowanie przy uploadzie <a class="header-anchor" href="#automatyczne-tagowanie-przy-uploadzie" aria-label="Permalink to &quot;Automatyczne tagowanie przy uploadzie&quot;">​</a></h2><p>Po włączeniu tej opcji nowo przesłane obrazy automatycznie wywołują skonfigurowane <code>Space URLs</code>.</p><p>Nadaje się to do długotrwałego użycia.</p><p>Jeśli Space ma kolejkę, sam upload może zakończyć się najpierw, a tagowanie będzie kontynuowane później.</p><h2 id="ktore-obrazy-sa-przetwarzane" tabindex="-1">Które obrazy są przetwarzane <a class="header-anchor" href="#ktore-obrazy-sa-przetwarzane" aria-label="Permalink to &quot;Które obrazy są przetwarzane&quot;">​</a></h2><p>Automatyczne tagowanie przetwarza głównie pliki obrazów.</p><p>Obrazy, które mają już kompletne tagi, orientację, rating, szerokość i wysokość, są pomijane, aby nie wykonywać niepotrzebnych wywołań Space.</p><p>ImgBed w miarę możliwości uzupełnia tylko brakujące informacje. Na przykład jeśli brakuje tylko orientacji, próbuje ją dodać bez pełnego procesu tagowania treści.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="dlaczego-duplikowac-własny-space" tabindex="-1">Dlaczego duplikować własny Space? <a class="header-anchor" href="#dlaczego-duplikowac-własny-space" aria-label="Permalink to &quot;Dlaczego duplikować własny Space?&quot;">​</a></h3><p>Publiczne Spaces są współdzielone przez wielu użytkowników. Własny zduplikowany Space jest używany głównie przez Twoją stronę ImgBed, więc zwykle działa szybciej i stabilniej.</p><h3 id="space-ciagle-sie-uruchamia" tabindex="-1">Space ciągle się uruchamia <a class="header-anchor" href="#space-ciagle-sie-uruchamia" aria-label="Permalink to &quot;Space ciągle się uruchamia&quot;">​</a></h3><p>Po pierwszym utworzeniu albo po długim okresie bezczynności Space może potrzebować czasu na start.</p><p>Najpierw otwórz stronę swojego Space. Gdy normalnie rozpozna obraz, wróć do ImgBed i rozpocznij tagowanie.</p><h3 id="jak-skopiowac-url-space" tabindex="-1">Jak skopiować URL Space? <a class="header-anchor" href="#jak-skopiowac-url-space" aria-label="Permalink to &quot;Jak skopiować URL Space?&quot;">​</a></h3><p>Otwórz stronę Hugging Face Space i skopiuj adres z przeglądarki.</p><p>Przykłady:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="czy-moge-dodac-wiele-spaces" tabindex="-1">Czy mogę dodać wiele Spaces? <a class="header-anchor" href="#czy-moge-dodac-wiele-spaces" aria-label="Permalink to &quot;Czy mogę dodać wiele Spaces?&quot;">​</a></h3><p>Tak. Wpisz jeden Space URL w każdym wierszu.</p><p>Wiele Spaces przetwarza obrazy razem i jest przydatne przy dużej liczbie obrazów.</p><h3 id="dlaczego-tagi-sa-po-angielsku" tabindex="-1">Dlaczego tagi są po angielsku? <a class="header-anchor" href="#dlaczego-tagi-sa-po-angielsku" aria-label="Permalink to &quot;Dlaczego tagi są po angielsku?&quot;">​</a></h3><p>Modele SmilingWolf zwracają tagi po angielsku. To normalne.</p><p>Tagi służą głównie do wyszukiwania, filtrowania, Random Image API i filtrów publicznej galerii.</p><h3 id="do-czego-słuza-tagi-ratingu" tabindex="-1">Do czego służą tagi ratingu? <a class="header-anchor" href="#do-czego-słuza-tagi-ratingu" aria-label="Permalink to &quot;Do czego służą tagi ratingu?&quot;">​</a></h3><p>Wyniki ratingu współpracują z trybem dostępu w Ustawieniach bezpieczeństwa.</p><p>Na przykład gdy dostęp odwiedzających jest ograniczony według wieku, publiczne przeglądanie i funkcje losowych obrazów filtrują obrazy według tych reguł.</p><h2 id="szybki-przebieg" tabindex="-1">Szybki przebieg <a class="header-anchor" href="#szybki-przebieg" aria-label="Permalink to &quot;Szybki przebieg&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Zaloguj się do Hugging Face</span></span>
<span class="line"><span>-&gt; Otwórz SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Poczekaj na zbudowanie Space</span></span>
<span class="line"><span>-&gt; Skopiuj URL swojego Space</span></span>
<span class="line"><span>-&gt; Wpisz Space URLs w ImgBed</span></span>
<span class="line"><span>-&gt; Wybierz model i progi</span></span>
<span class="line"><span>-&gt; Rozpocznij tagowanie albo włącz automatyczne tagowanie przy uploadzie</span></span></code></pre></div>`,63)])])}const y=t(c,[["render",p]]);export{u as __pageData,y as default};
